from dataclasses import dataclass, field
from datetime import date, timedelta
from pathlib import Path
from typing import Optional
import yaml

SLA_DAYS: dict[str, dict[str, int]] = {
    "P1": {"triage": 1,  "fix": 14},
    "P2": {"triage": 3,  "fix": 30},
    "P3": {"triage": 7,  "fix": 90},
    "P4": {"triage": 14, "fix": 180},
}

ESCALATION_OWNERS: dict[str, str] = {
    "P1": "ciso + vp-eng",
    "P2": "platform-lead",
    "P3": "monthly-review",
    "P4": "quarterly-review",
}

@dataclass
class Finding:
    id: str
    title: str
    priority: str
    status: str
    discovered_at: date
    fix_sla: Optional[date]
    owner: Optional[str]
    dimension: str

    @property
    def triage_deadline(self) -> date:
        return self.discovered_at + timedelta(days=SLA_DAYS[self.priority]["triage"])

    @property
    def fix_deadline(self) -> date:
        return self.discovered_at + timedelta(days=SLA_DAYS[self.priority]["fix"])

    @property
    def days_until_fix_sla(self) -> int:
        return (self.fix_deadline - date.today()).days

    @property
    def is_breached(self) -> bool:
        if self.status in ("CLOSED", "WONT_FIX"):
            return False
        if self.status == "OPEN" and date.today() > self.triage_deadline:
            return True
        return date.today() > self.fix_deadline

    @property
    def needs_escalation(self) -> bool:
        return self.is_breached and self.status not in ("ESCALATED", "CLOSED", "WONT_FIX")

    def status_line(self) -> str:
        breach = " *** BREACH ***" if self.is_breached else ""
        days = self.days_until_fix_sla
        return (
            f"{self.id:12s}  {self.priority}  {self.status:12s}  "
            f"dim={self.dimension:15s}  "
            f"sla_days={days:+4d}  "
            f"owner={self.owner or 'UNASSIGNED'}{breach}"
        )


def load_findings(findings_dir: str) -> list[Finding]:
    findings = []
    for path in Path(findings_dir).glob("*.yaml"):
        raw = yaml.safe_load(path.read_text())
        findings.append(Finding(
            id=raw["id"],
            title=raw["title"],
            priority=raw["priority"],
            status=raw["status"],
            discovered_at=date.fromisoformat(str(raw["discovered_at"])),
            fix_sla=date.fromisoformat(str(raw["remediation"]["fix_sla"]))
                    if raw.get("remediation", {}).get("fix_sla") else None,
            owner=raw.get("remediation", {}).get("owner"),
            dimension=raw["dimension"],
        ))
    return sorted(findings, key=lambda f: (f.priority, f.discovered_at))


def generate_daily_report(findings_dir: str) -> dict:
    findings = load_findings(findings_dir)
    open_findings = [f for f in findings if f.status not in ("CLOSED", "WONT_FIX")]
    breached = [f for f in open_findings if f.is_breached]
    due_soon = [f for f in open_findings if 0 < f.days_until_fix_sla <= 7 and not f.is_breached]

    print(f"=== Finding Tracker Daily Report — {date.today()} ===")
    print(f"Open: {len(open_findings)}  Breached: {len(breached)}  Due ≤7 days: {len(due_soon)}")
    print()
    for f in open_findings:
        print(f.status_line())

    return {"open": len(open_findings), "breached": len(breached), "due_soon": len(due_soon)}

from datetime import date
from collections import defaultdict

def compute_mttr(findings: list) -> dict[str, float]:
    closed = [f for f in findings if f.status == "CLOSED" and hasattr(f, "closed_at")]
    mttr_by_priority: dict[str, list[int]] = defaultdict(list)
    for f in closed:
        days = (f.closed_at - f.discovered_at).days
        mttr_by_priority[f.priority].append(days)
    return {
        p: sum(days) / len(days)
        for p, days in mttr_by_priority.items()
        if days
    }

def backlog_trend(findings: list, months: int = 6) -> list[dict]:
    snapshots = []
    today = date.today()
    for m in range(months, -1, -1):
        # Approximate: count findings open at end of month m
        snapshot_date = date(today.year, ((today.month - m - 1) % 12) + 1, 28)
        open_at_snapshot = [
            f for f in findings
            if f.discovered_at <= snapshot_date
            and (f.status not in ("CLOSED", "WONT_FIX") or
                 getattr(f, "closed_at", date.max) > snapshot_date)
        ]
        snapshots.append({
            "month": snapshot_date.strftime("%Y-%m"),
            "open": len(open_at_snapshot),
            "p1": sum(1 for f in open_at_snapshot if f.priority == "P1"),
            "p2": sum(1 for f in open_at_snapshot if f.priority == "P2"),
        })
    return snapshots
